const requiredVars = ['PORT','DB_URL','JWT_SECRET','SMS_USER','SMS_PASS'];
const missing = requiredVars.filter(v => !process.env[v]);
if(missing.length) { console.error(`Missing env vars: ${missing.join(', ')}`); process.exit(1); }
module.exports = { port: process.env.PORT, dbUrl: process.env.DB_URL, jwtSecret: process.env.JWT_SECRET, smsUser: process.env.SMS_USER, smsPass: process.env.SMS_PASS };
